const err = $input.item.json;
const workflowName = err.workflow?.name || 'Unknown';
const nodeName = err.execution?.lastNodeExecuted || 'Unknown';
const errorMsg = err.execution?.error?.message || 'Unknown error';
const execId = err.execution?.id || '';

const msg = `🚨 *JARVIS Error Report*\n\n*Workflow:* ${workflowName}\n*Node:* ${nodeName}\n*Error:* \`${errorMsg}\`\n*Execution:* ${execId}\n*Time:* ${new Date().toISOString()}`;

return [{ json: { message: msg, workflowName, errorMsg } }];
